transform_js:
var ranges = rawData.rows.map(function(r) { return r.range; });
var volumes = rawData.rows.map(function(r) { return r.vol; });
transformedData = { ranges: ranges, volumes: volumes };

echarts_js:
option = {
  title: { text: 'Volume Profile (Price)', left: 'center' },
  tooltip: { trigger: 'axis' },
  grid: { left: '20%', right: '10%' },
  yAxis: { type: 'category', data: transformedData.ranges, name: 'Price Range' },
  xAxis: { type: 'value', name: 'Volume' },
  series: [{
    type: 'bar',
    data: transformedData.volumes,
    itemStyle: {
      color: function(p) {
        var maxV = Math.max.apply(null, transformedData.volumes);
        var ratio = p.value / maxV;
        return ratio > 0.8 ? '#ee6666' : ratio > 0.5 ? '#fac858' : '#5470c6';
      }
    },
    barWidth: '70%'
  }]
};
